import{_ as a,o,c as t,ae as n}from"./chunks/framework.BMBGeRFM.js";const b=JSON.parse(`{"title":"Wait, Why Didn't Anybody Tell Me?","description":"","frontmatter":{"title":"Wait, Why Didn't Anybody Tell Me?","date":"2026-04-18T00:00:00.000Z"},"headers":[],"relativePath":"news/2026-04-18-semver.md","filePath":"news/2026-04-18-semver.md"}`),r={name:"news/2026-04-18-semver.md"};function s(i,e,c,d,l,h){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="farben-now-follows-semver-0-x-thing" tabindex="-1">Farben Now Follows SemVer 0.x thing <a class="header-anchor" href="#farben-now-follows-semver-0-x-thing" aria-label="Permalink to &quot;Farben Now Follows SemVer 0.x thing&quot;">​</a></h1><h2 id="backstory" tabindex="-1">Backstory <a class="header-anchor" href="#backstory" aria-label="Permalink to &quot;Backstory&quot;">​</a></h2><p>So apparently I didn&#39;t know that SemVer has a special case for projects on <code>0.x</code>, which is what Farben currently is at the moment. It reads, basically a <code>0.x+1</code> update is the same as a major, breaking update.</p><p>I could&#39;ve ignored it, until I noticed Crates-io follow that rule! Uh oh, my bad for the inconveniences. The Farben public-facing API crate has had nothing short of maybe 3-4 breaking releases (ignore what crates-io says), while <code>core</code> has had the most breaking releases, you know, being internals and all needs constant modifications in new features.</p><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>So from now on, which is version <code>frb0.17.1</code>, I am following the <code>0.x+1</code> semver thing! You should see it with update <code>frb0.17.2</code>, which I intended to be <code>frb0.18</code> before finding out about this.</p><p>This is so embarassing. Just make great things with Farben...</p><p>Cheers, RazkarStudio.</p>',8)])])}const u=a(r,[["render",s]]);export{b as __pageData,u as default};
